/***** PDEV → Airtable updater (Updated Fields + Process Only Logic) *****/
const rec = $input.item?.json ?? {};
const id  = typeof rec.id === "string" ? rec.id.trim() : "";

// helpers to read from either flat or { fields: {...} } shapes
const get = (name) => rec[name] !== undefined ? rec[name] : rec.fields?.[name];
const has = (name) =>
  rec[name] !== undefined ||
  (rec.fields && Object.prototype.hasOwnProperty.call(rec.fields, name));

const isEmpty = (v) =>
  v == null
    ? true
    : Array.isArray(v)
      ? v.length === 0
      : (typeof v === "string" ? v.trim() === "" : false);

if (!id) {
  return { json: { _skip: true, reason: "missing id", sourceIndex: $itemIndex } };
}

/** ── Config ────────────────────────────────────────────────────────────── **/
const STATUS_FIELD_CANDIDATES = ["Status", "PDEV Status", "Requirement Status"];
const INITIAL_PEC_FIELD_CANDIDATES = ["INITIAL PEC", "Initial PEC", "Initial Pec"];
const REQ_TYPE_FIELD_CANDIDATES = ["REQ TYPE", "Req Type", "Request Type"];

const ONGOING_STATUSES = new Set(["Ongoing", "In Progress", "Active"]);
const OVERDUE_DAYS = 14;   // PEC older than this ⇒ overdue
/** ─────────────────────────────────────────────────────────────────────── **/

// 1. UPDATED: The new list of fields to check
const CHECK_FIELDS = [
  "Client",
  "Company",
  "Process Engineer",
  "POTENTIAL MVA", // <--- Skipped if Process Only
  "REQ TYPE",
  "INITIAL PEC",
  "JD + C",        // <--- Skipped if Process Only
  "VA Title",
  "Scope Type"
];

// 2. LOGIC: Determine if REQ TYPE is "PROCESS ONLY"
const normalizeText = (v) => {
  const s = (typeof v === "object" && v?.name != null) ? String(v.name) : String(v ?? "");
  return s.trim();
};

const reqTypeRaw =
  REQ_TYPE_FIELD_CANDIDATES
    .map((f) => get(f))
    .find((v) => normalizeText(v) !== "") ?? "";

const isProcessOnly = normalizeText(reqTypeRaw).toLowerCase() === "process only";

// 3. LOGIC: Filter the required fields list
// If Process Only is TRUE, we remove "POTENTIAL MVA" AND "JD + C" from the check list.
const fieldsToExclude = ["POTENTIAL MVA", "JD + C"];

const REQUIRED_FIELDS = isProcessOnly
  ? CHECK_FIELDS.filter((f) => !fieldsToExclude.includes(f))
  : CHECK_FIELDS;

let missing = REQUIRED_FIELDS.filter((name) => isEmpty(get(name)));
let actionItems = [];

// Pick the status & PEC fields that actually exist
const STATUS_FIELD = STATUS_FIELD_CANDIDATES.find((f) => has(f)) || STATUS_FIELD_CANDIDATES[0];
const PEC_FIELD    = INITIAL_PEC_FIELD_CANDIDATES.find((f) => has(f)) || INITIAL_PEC_FIELD_CANDIDATES[0];

const status = String(get(STATUS_FIELD) ?? "").trim();
const isOngoing = ONGOING_STATUSES.has(status);

const fields = {
  "Last Scrubbed At": new Date().toISOString(),
};

// 4. PEC LOGIC (Age check only)
if (isOngoing) {
  const pecRaw = get(PEC_FIELD);

  if (!isEmpty(pecRaw)) {
    // Validate/age PEC
    const pec = new Date(pecRaw);
    if (!Number.isNaN(pec.getTime())) {
      const ageDays = Math.floor((Date.now() - pec.getTime()) / 86400000);
      fields["PEC Age (days)"] = ageDays;
      const overdue = ageDays > OVERDUE_DAYS;
      fields["PEC Overdue?"] = overdue;
      if (overdue) {
        actionItems.push(`${PEC_FIELD} is ${ageDays} days old — follow up`);
      }
    } else {
      // If it exists but isn't a date, flag it
      if (!missing.includes(PEC_FIELD)) missing.push(PEC_FIELD);
      actionItems.push(`Fix invalid ${PEC_FIELD} datetime`);
    }
  }
}

// Finalize scrubbing flags & notes
fields["For Scrubbing?"] = (missing.length > 0) || fields["PEC Overdue?"] === true;
fields["Fields with Missing Data"] = missing.join(", ");
if (actionItems.length) fields["Action Items"] = actionItems.join(" • ");

// Logic Note: Helpful log for why fields were skipped
if (isProcessOnly) {
  // We append to existing notes or create new ones
  const currentNote = normalizeText(get("Notes (System)")) || "";
  const exemptionNote = "Exemptions: MVA & JD+C skipped (REQ TYPE is PROCESS ONLY)";

  // Only add the note if it isn't already there to avoid duplication on repeated runs
  if (!currentNote.includes("PROCESS ONLY")) {
     fields["Notes (System)"] = [currentNote, exemptionNote].filter(Boolean).join(" | ");
  }
}

return { json: { id, fields } };

/***** Aggregate PDEV Metrics — Daily Scrubbing row (adds hyperlink JSON) *****
 * Place: after the PDEV Loop node ("done" port)
 * LOOKUP_NODE: your PDEV search node (has primary names)
 ******************************************************************************/

const LOOKUP_NODE = "PDEV Ongoing Requirements";      // search
const TABLE_NAME  = "PDEV Requirements";
const PRIMARY_NAME_FIELD = "PDEV Requirement";        // primary name in that table

// ---------- gather inputs (FIXED) ----------
// Use $input.all() so we see ALL items from the loop, not just the last batch
const detectorItems = $input.all();
const lookupItems   = $(LOOKUP_NODE).all();
const scanned = detectorItems.length;

// ---------- build ID→Name map from lookup results ----------
const nameById = new Map();
for (const it of lookupItems) {
  const j  = it.json || {};
  const id = String(j.id || j.recordId || j?.fields?.id || "").trim();
  const nm =
    j?.fields?.[PRIMARY_NAME_FIELD] ??
    j[PRIMARY_NAME_FIELD] ??
    j?.fields?.name ??
    j.name;
  if (id && nm) nameById.set(id, String(nm).trim());
}

// Sensible fallback if primary field is empty
const derivePDEVName = (f = {}) => {
  // Try common PDEV fields you might have; tweak as needed for your base
  return (
    f["PDEV Requirement"] ||
    (f["Client Name"] && f["Role Title"] ? `${f["Client Name"]} - ${f["Role Title"]}` : null) ||
    f["Role Title"] ||
    f["Client Name"] ||
    f["Name"] ||
    "(No name)"
  );
};

// ---------- tally + per-record capture ----------
let flagged = 0;
let forScrubbingCount = 0;
const tally = Object.create(null);
const perRecord = [];
const alias = (s) => String(s).replace(/\s*\[Link\]\s*$/i, "");

for (const it of detectorItems) {
  const j = it.json || {};
  const f = j.fields || {};
  const id = String(j.id || j.recordId || j?.fields?.id || "").trim();

  // FIX: Robust check for true or "true"
  if (f["For Scrubbing?"] === true || f["For Scrubbing?"] === "true") {
    flagged++;
    forScrubbingCount++;
  }

  const list = String(f["Fields with Missing Data"] || "")
    .split(/[,\n;]+/)
    .map(s => alias(s.trim()))
    .filter(Boolean);

  const seen = new Set();
  const missing = [];
  for (const key of list) {
    if (!seen.has(key)) {
      seen.add(key);
      missing.push(key);
      tally[key] = (tally[key] || 0) + 1;
    }
  }

  if (missing.length) {
    perRecord.push({
      id,
      name: nameById.get(id) || derivePDEVName(f),
      missing,
      missing_count: missing.length,
    });
  }
}

// ---------- global top-missing fields ----------
const top_missing_json = Object.entries(tally)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10);

// ---------- pick top records (for human + machine) ----------
perRecord.sort((a, b) => (b.missing_count - a.missing_count) || a.name.localeCompare(b.name));

const TOP_N = 5;
const MAX_FIELDS_PER_LINE = 5;

const topRecords = perRecord.slice(0, TOP_N);

// human lines
const lines = topRecords.map(r => {
  const shown = r.missing.slice(0, MAX_FIELDS_PER_LINE);
  const extra = r.missing.length - shown.length;
  return `• ${r.name} — ${shown.join(", ")}${extra > 0 ? `, +${extra} more` : ""}`;
});

// machine helpers for hyperlinks
const nameIdMap = {};
const topNames  = [];
const topIds    = [];
const topRecordsSlim = [];

for (const r of topRecords) {
  if (r.name && r.id) nameIdMap[r.name] = r.id;
  topNames.push(r.name);
  topIds.push(r.id);
  topRecordsSlim.push({
    id: r.id,
    name: r.name,
    missing: r.missing,
    missing_count: r.missing_count,
  });
}

// ---------- final payload ----------
const humanBlock = lines.join("\n") + (lines.length ? "\n" : "");

return [{
  json: {
    table: TABLE_NAME,
    date_scrubbed: new Date().toISOString(),
    run_id: $json.run_id || (Date.now().toString(36) + Math.random().toString(36).slice(2,8)),
    scanned,
    flagged,
    cleared: 0,
    for_scrubbing_count: forScrubbingCount,
    top_missing_json,

    // Human
    display_missing_records: humanBlock,
    display_missing_fields:  humanBlock,

    // Structured (optional)
    display_missing_records_lines: lines,
    display_missing_records_json:  topRecordsSlim,

    // 🔗 JSON-with-IDs for the Daily row (map these to Long text fields in Airtable)
    "Top Records (JSON)":     JSON.stringify(topRecordsSlim),
    "Name→ID Map (JSON)":     JSON.stringify(nameIdMap),
    "Top Record IDs (JSON)":  JSON.stringify(topIds),
    "Top Names (JSON)":       JSON.stringify(topNames),
    "Display Missing (JSON)": JSON.stringify(topRecordsSlim),
  }
}];

/**
 * US/Sunday-start week labels in PHT, with table initials appended.
 * Example week_label: "2025-W42-VA"
 */

const agg = items[0]?.json ?? {};

// ---------- helpers (PHT) ----------
const pad = (n) => String(n).padStart(2, '0');
const toPHT = (d) => {
  const utcMs = d.getTime() + d.getTimezoneOffset() * 60000;
  return new Date(utcMs + 8 * 3600000); // UTC+8
};
const sundayStartPHT = (dPHT) => {
  const x = new Date(dPHT);
  const dow = x.getDay(); // Sun=0..Sat=6
  x.setDate(x.getDate() - dow); // rewind to Sunday
  x.setHours(0,0,0,0);
  return x;
};
const yyyymmddNum = (d) =>
  Number(`${d.getFullYear()}${pad(d.getMonth() + 1)}${pad(d.getDate())}`);

/** US-style week label (Sunday-start, Jan-1 rule), e.g. 2025-W42 */
const weekLabelUS = (dPHT) => {
  const year = dPHT.getFullYear();
  const jan1 = new Date(year, 0, 1);
  jan1.setHours(0,0,0,0);
  const jan1PHT = toPHT(jan1);
  const days = Math.floor((dPHT - jan1PHT) / 86400000);
  const week = Math.floor((days + jan1PHT.getDay()) / 7) + 1;
  return `${year}-W${String(week).padStart(2, '0')}`;
};

/** Derive initials for the table (with a few explicit mappings) */
const tableInitials = (name) => {
  const map = {
    'Virtual Assistants': 'VA',
    'Placements Requirements': 'PR',
    'PDEV Requirements': 'PDEV',
    'PDEV Ongoing Requirements': 'PDEV',
  };
  if (map[name]) return map[name];

  // Generic fallback: take first letters of words, up to 6 chars
  const words = String(name || '')
    .split(/[^A-Za-z0-9]+/)
    .filter(Boolean);
  if (words.length === 0) return 'GEN';

  // If it's already an acronym like "PDEV" or "VA", keep it
  const allCaps = words.join('').match(/^[A-Z0-9]{2,}$/);
  if (allCaps) return allCaps[0].slice(0, 6);

  return words.map(w => w[0].toUpperCase()).join('').slice(0, 6);
};

// ---------- small utils ----------
const tryParse = (v) => {
  if (v == null) return null;
  if (Array.isArray(v) || typeof v === 'object') return v;
  if (typeof v !== 'string') return null;
  try { return JSON.parse(v); } catch { return null; }
};

// ---------- compute (now in PHT) ----------
const nowPHT = toPHT(new Date());
const day_key = yyyymmddNum(nowPHT);
const weekStart = sundayStartPHT(nowPHT);   // Sunday-start week
const week_key = yyyymmddNum(weekStart);    // numeric key = Sunday (PHT) of this week
const week_start_pht = weekStart.toISOString();
const week_label_plain = weekLabelUS(nowPHT);   // e.g., "2025-W42"

// ---------- normalize aggregate fields ----------
const table_name = agg.table_name || agg.table || agg.Table || 'Virtual Assistants';
const initials = tableInitials(table_name);
const week_label = `${week_label_plain}-${initials}`; // e.g., "2025-W42-VA"

const scanned = agg.scanned ?? agg.Scanned ?? 0;
const flagged = agg.flagged ?? agg.Flagged ?? 0;
const cleared = agg.cleared ?? agg.Cleared ?? 0;
const run_id = agg.run_id ?? agg.RunID ?? agg['Run ID'] ?? $execution.id ?? null;

let top_missing_json = agg.top_missing_json ?? agg['Top Missing (JSON)'] ?? [];
if (typeof top_missing_json === 'string') {
  try { top_missing_json = JSON.parse(top_missing_json); } catch { /* keep as string */ }
}

const for_scrubbing_count = agg.for_scrubbing_count ?? flagged;

// ---------- passthroughs ----------
const display_missing_records =
  agg.display_missing_records ?? agg['Display Missing Records'] ?? '';

let display_missing_records_lines =
  agg.display_missing_records_lines ?? agg['Display Missing Records (Lines)'] ?? [];
if (typeof display_missing_records_lines === 'string') {
  try {
    display_missing_records_lines = JSON.parse(display_missing_records_lines);
  } catch {
    display_missing_records_lines = display_missing_records
      ? String(display_missing_records).split(/\r?\n/).filter(Boolean)
      : [];
  }
}

let display_missing_records_json =
  agg.display_missing_records_json ?? agg['Display Missing Records (JSON)'] ?? [];
if (typeof display_missing_records_json === 'string') {
  try { display_missing_records_json = JSON.parse(display_missing_records_json); } catch { display_missing_records_json = []; }
}

// ---------- NEW: hydrate IDs for a new machine field: display_missing_json ----------
/*
  We’ll look for any of these optional helper fields on the aggregate:
  - "Top Records (JSON)"     -> [{ id, name, missing?, missing_count? }]
  - "Name→ID Map (JSON)"     -> { "<name>": "rec..." }
  - "Top Record IDs (JSON)"  -> ["rec...", ...] (positional)
  - "Top Names (JSON)"       -> ["Name A", ...] (positional with Top Record IDs)
*/
const topRecordsJSON = tryParse(agg['Top Records (JSON)']) || tryParse(agg.top_records_json);
const nameToIdMap    = tryParse(agg['Name→ID Map (JSON)']) || tryParse(agg.name_id_map_json) || {};
const topIdsArray    = tryParse(agg['Top Record IDs (JSON)']) || tryParse(agg.top_record_ids_json) || [];
const topNamesArray  = tryParse(agg['Top Names (JSON)']) || tryParse(agg.top_names_json) || [];

// Build a normalized name→id dictionary
const nameToId = {};
if (topRecordsJSON && Array.isArray(topRecordsJSON)) {
  for (const r of topRecordsJSON) {
    const nm = (r?.name || '').toString().trim();
    const id = (r?.id || '').toString().trim();
    if (nm && id) nameToId[nm] = id;
  }
}
if (nameToIdMap && typeof nameToIdMap === 'object') {
  for (const [nm, id] of Object.entries(nameToIdMap)) {
    const n = (nm || '').toString().trim();
    const i = (id || '').toString().trim();
    if (n && i) nameToId[n] = i;
  }
}

// Positional fallback if we have both names & ids arrays of same length
const hasPositional = Array.isArray(topIdsArray) &&
  (Array.isArray(topNamesArray) ? topNamesArray.length === topIdsArray.length : true);

// Ensure we have an array of objects to enrich (name + missing info)
let baseArray = [];
if (Array.isArray(display_missing_records_json) && display_missing_records_json.length) {
  baseArray = display_missing_records_json.map(x => ({
    name: x.name || x.display_name || x.title || "",
    missing: Array.isArray(x.missing) ? x.missing : (Array.isArray(x.missing_fields) ? x.missing_fields : []),
    missing_count: (x.missing_count != null) ? x.missing_count
                  : (Array.isArray(x.missing) ? x.missing.length
                  : (Array.isArray(x.missing_fields) ? x.missing_fields.length : 0)),
    id: x.id || x.recId || x.origin_recId || null,
  }));
} else {
  // fallback from lines-only: convert to objects without ids
  baseArray = display_missing_records_lines.map(line => {
    // split on last em/en/spaced hyphen
    const parts = (() => {
      const cands = [' — ', ' – ', ' - '];
      for (const sep of cands) {
        const idx = line.lastIndexOf(sep);
        if (idx > 0 && idx < line.length - sep.length) return [line.slice(0, idx), line.slice(idx + sep.length)];
      }
      return [line, ""];
    })();
    const name = parts[0].replace(/^\s*[•\u2022-]\s*/, '').trim();
    const fields = parts[1]
      .split(/[;,]/).map(s => s.trim()).filter(Boolean)
      .map(s => s.replace(/[.\s]+$/g, ''))
      .filter(s => !/^\+\d+\s*more$/i.test(s));
    const extra = (parts[1].match(/\+(\d+)\s*more/i)?.[1]) ? Number(RegExp.$1) : 0;
    return {
      name,
      missing: fields,
      missing_count: fields.length + extra,
      id: null,
    };
  });
}

// Enrich with IDs by name and/or by position
const display_missing_json = baseArray.map((row, idx) => {
  let id = row.id || null;
  const nameTrim = (row.name || '').toString().trim();
  if (!id && nameTrim && nameToId[nameTrim]) id = nameToId[nameTrim];
  if (!id && hasPositional && idx < (topIdsArray?.length || 0)) {
    const posId = (topIdsArray[idx] || '').toString().trim();
    if (posId) id = posId;
  }
  return {
    id: id || null,
    name: nameTrim || "(No name)",
    missing: Array.isArray(row.missing) ? row.missing : [],
    missing_count: row.missing_count != null ? row.missing_count : (Array.isArray(row.missing) ? row.missing.length : 0),
  };
});

const date_pht = nowPHT.toISOString();
const date_scrubbed = date_pht;

return [{
  json: {
    table: table_name,
    date_scrubbed,
    run_id,
    scanned,
    flagged,
    cleared,
    for_scrubbing_count,
    top_missing_json,
    day_key,
    date_pht,
    week_key,          // Sunday (PHT) YYYYMMDD
    week_start_pht,    // ISO of that Sunday 00:00 PHT
    week_label,        // with initials, e.g. "2025-W42-VA"
    week_label_plain,  // optional: "2025-W42"
    table_name,
    table_initials: initials,

    // ---------- passthroughs ----------
    display_missing_records,
    display_missing_records_lines,
    display_missing_records_json,

    // ---------- NEW: with record IDs for Slack / downstream ----------
    display_missing_json,                   // array (machine field)
    "Display Missing (JSON)": JSON.stringify(display_missing_json), // stringified for Airtable long-text
  }
}];

/***** PDEV → Airtable updater (Contract & Finance Scrubbing) *****/
const rec = $input.item?.json ?? {};
const id  = typeof rec.id === "string" ? rec.id.trim() : "";

// helpers to read from either flat or { fields: {...} } shapes
const get = (name) => rec[name] !== undefined ? rec[name] : rec.fields?.[name];
const has = (name) =>
  rec[name] !== undefined ||
  (rec.fields && Object.prototype.hasOwnProperty.call(rec.fields, name));

const isEmpty = (v) =>
  v == null
    ? true
    : Array.isArray(v)
      ? v.length === 0
      : (typeof v === "string" ? v.trim() === "" : false);

if (!id) {
  return { json: { _skip: true, reason: "missing id", sourceIndex: $itemIndex } };
}

/** ── Config ────────────────────────────────────────────────────────────── **/
const STATUS_FIELD_CANDIDATES = ["Status", "PDEV Status", "Requirement Status"];
const INITIAL_PEC_FIELD_CANDIDATES = ["INITIAL PEC", "Initial PEC", "Initial Pec"];
const REQ_TYPE_FIELD_CANDIDATES = ["REQ TYPE", "Req Type", "Request Type"];

const ONGOING_STATUSES = new Set(["Ongoing", "In Progress", "Active"]);
const OVERDUE_DAYS = 14;   // PEC older than this ⇒ overdue
/** ─────────────────────────────────────────────────────────────────────── **/

// 1. UPDATED: The new strict list of fields to check
const CHECK_FIELDS = [
  "SUF Paid Amount",
  "SUF Paid On",
  "RFP Received Date",
  "CSA Signed On",
  "RFP",
  "CSA",
  "Sales Closer",
  "Prepared By"
];

// 2. LOGIC: Determine if REQ TYPE is "PROCESS ONLY"
// (Kept for system notes logging, but removed from filtering logic as requested)
const normalizeText = (v) => {
  const s = (typeof v === "object" && v?.name != null) ? String(v.name) : String(v ?? "");
  return s.trim();
};

const reqTypeRaw =
  REQ_TYPE_FIELD_CANDIDATES
    .map((f) => get(f))
    .find((v) => normalizeText(v) !== "") ?? "";

const isProcessOnly = normalizeText(reqTypeRaw).toLowerCase() === "process only";

// 3. LOGIC: Filter the required fields list
// User requested "without any consideration", so we do NOT exclude fields based on Process Only.
// All fields in CHECK_FIELDS are required.
const fieldsToExclude = []; 

const REQUIRED_FIELDS = isProcessOnly
  ? CHECK_FIELDS.filter((f) => !fieldsToExclude.includes(f))
  : CHECK_FIELDS;

let missing = REQUIRED_FIELDS.filter((name) => isEmpty(get(name)));
let actionItems = [];

// Pick the status & PEC fields that actually exist
const STATUS_FIELD = STATUS_FIELD_CANDIDATES.find((f) => has(f)) || STATUS_FIELD_CANDIDATES[0];
const PEC_FIELD    = INITIAL_PEC_FIELD_CANDIDATES.find((f) => has(f)) || INITIAL_PEC_FIELD_CANDIDATES[0];

const status = String(get(STATUS_FIELD) ?? "").trim();
const isOngoing = ONGOING_STATUSES.has(status);

const fields = {
  "Last Scrubbed At": new Date().toISOString(),
};

// 4. PEC LOGIC (Age check only - kept as utility)
if (isOngoing) {
  const pecRaw = get(PEC_FIELD);

  if (!isEmpty(pecRaw)) {
    // Validate/age PEC
    const pec = new Date(pecRaw);
    if (!Number.isNaN(pec.getTime())) {
      const ageDays = Math.floor((Date.now() - pec.getTime()) / 86400000);
      fields["PEC Age (days)"] = ageDays;
      const overdue = ageDays > OVERDUE_DAYS;
      fields["PEC Overdue?"] = overdue;
      if (overdue) {
        actionItems.push(`${PEC_FIELD} is ${ageDays} days old — follow up`);
      }
    } else {
      // If it exists but isn't a date, flag it
      actionItems.push(`Fix invalid ${PEC_FIELD} datetime`);
    }
  }
}

// Finalize scrubbing flags & notes
fields["For Scrubbing?"] = (missing.length > 0) || fields["PEC Overdue?"] === true;
fields["Fields with Missing Data"] = missing.join(", ");
if (actionItems.length) fields["Action Items"] = actionItems.join(" • ");

// Logic Note: Helpful log for system notes
if (isProcessOnly) {
  const currentNote = normalizeText(get("Notes (System)")) || "";
  // We still log that it is Process Only, but we no longer list exemptions
  const typeNote = "[System] Record is PROCESS ONLY";

  if (!currentNote.includes("PROCESS ONLY")) {
     fields["Notes (System)"] = [currentNote, typeNote].filter(Boolean).join(" | ");
  }
}

return { json: { id, fields } };

/***** Aggregate Projects Metrics — Daily Scrubbing row (adds hyperlink JSON) *****
 * Place: after the Projects Loop node ("done" port)
 * NOTE: Ensure your previous node passes "Project ID" through in the output!
 ******************************************************************************/

const TABLE_NAME = "Projects";
const PRIMARY_NAME_FIELD = "Project ID"; // As requested

// ---------- gather inputs ----------
// Use $input.all() so we see ALL items from the loop
const detectorItems = $input.all();
const scanned = detectorItems.length;

// Sensible fallback if Project ID is somehow missing
const deriveProjectName = (f = {}, j = {}) => {
  return (
    f[PRIMARY_NAME_FIELD] || // Look in fields
    j[PRIMARY_NAME_FIELD] || // Look in root json
    j.name ||                // Look for generic name property
    f["Project Name"] ||
    f["Client"] ||
    "(No Project ID)"
  );
};

// ---------- tally + per-record capture ----------
let flagged = 0;
let forScrubbingCount = 0;
const tally = Object.create(null);
const perRecord = [];
const alias = (s) => String(s).replace(/\s*\[Link\]\s*$/i, "");

for (const it of detectorItems) {
  const j = it.json || {};
  const f = j.fields || {};
  const id = String(j.id || j.recordId || j?.fields?.id || "").trim();

  // FIX: Robust check for true or "true"
  if (f["For Scrubbing?"] === true || f["For Scrubbing?"] === "true") {
    flagged++;
    forScrubbingCount++;
  }

  const list = String(f["Fields with Missing Data"] || "")
    .split(/[,\n;]+/)
    .map(s => alias(s.trim()))
    .filter(Boolean);

  const seen = new Set();
  const missing = [];
  for (const key of list) {
    if (!seen.has(key)) {
      seen.add(key);
      missing.push(key);
      tally[key] = (tally[key] || 0) + 1;
    }
  }

  // Get the name directly from the item since there is no lookup
  const recordName = deriveProjectName(f, j);

  if (missing.length) {
    perRecord.push({
      id,
      name: recordName,
      missing,
      missing_count: missing.length,
    });
  }
}

// ---------- global top-missing fields ----------
const top_missing_json = Object.entries(tally)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10);

// ---------- pick top records (for human + machine) ----------
perRecord.sort((a, b) => (b.missing_count - a.missing_count) || a.name.localeCompare(b.name));

const TOP_N = 5;
const MAX_FIELDS_PER_LINE = 5;

const topRecords = perRecord.slice(0, TOP_N);

// human lines
const lines = topRecords.map(r => {
  const shown = r.missing.slice(0, MAX_FIELDS_PER_LINE);
  const extra = r.missing.length - shown.length;
  return `• ${r.name} — ${shown.join(", ")}${extra > 0 ? `, +${extra} more` : ""}`;
});

// machine helpers for hyperlinks
const nameIdMap = {};
const topNames  = [];
const topIds    = [];
const topRecordsSlim = [];

for (const r of topRecords) {
  if (r.name && r.id) nameIdMap[r.name] = r.id;
  topNames.push(r.name);
  topIds.push(r.id);
  topRecordsSlim.push({
    id: r.id,
    name: r.name,
    missing: r.missing,
    missing_count: r.missing_count,
  });
}

// ---------- final payload ----------
const humanBlock = lines.join("\n") + (lines.length ? "\n" : "");

return [{
  json: {
    table: TABLE_NAME,
    date_scrubbed: new Date().toISOString(),
    run_id: $json.run_id || (Date.now().toString(36) + Math.random().toString(36).slice(2,8)),
    scanned,
    flagged,
    cleared: 0,
    for_scrubbing_count: forScrubbingCount,
    top_missing_json,

    // Human
    display_missing_records: humanBlock,
    display_missing_fields:  humanBlock,

    // Structured (optional)
    display_missing_records_lines: lines,
    display_missing_records_json:  topRecordsSlim,

    // 🔗 JSON-with-IDs for the Daily row
    "Top Records (JSON)":     JSON.stringify(topRecordsSlim),
    "Name→ID Map (JSON)":     JSON.stringify(nameIdMap),
    "Top Record IDs (JSON)":  JSON.stringify(topIds),
    "Top Names (JSON)":       JSON.stringify(topNames),
    "Display Missing (JSON)": JSON.stringify(topRecordsSlim),
  }
}];

/***** Projects → Daily Scrubbing Row Prep (PHT & JSON Hydration) *****/

// 1. Get input
// (Safely handle cases where input might be empty)
const items = $input.all();
const agg = items.length > 0 && items[0].json ? items[0].json : {};

// 2. Helper Functions

// Pad numbers (01, 02...)
const pad = (n) => String(n).padStart(2, '0');

// Convert Date to PHT (UTC+8)
const toPHT = (d) => {
  const utcMs = d.getTime() + d.getTimezoneOffset() * 60000;
  return new Date(utcMs + 8 * 3600000);
};

// Get Sunday start (PHT)
const sundayStartPHT = (dPHT) => {
  const x = new Date(dPHT);
  const dow = x.getDay(); // Sun=0..Sat=6
  x.setDate(x.getDate() - dow); // rewind to Sunday
  x.setHours(0,0,0,0);
  return x;
};

// YYYYMMDD Number
const yyyymmddNum = (d) =>
  Number(`${d.getFullYear()}${pad(d.getMonth() + 1)}${pad(d.getDate())}`);

// US Week Label (e.g. 2025-W05)
const weekLabelUS = (dPHT) => {
  const year = dPHT.getFullYear();
  const jan1 = new Date(year, 0, 1);
  jan1.setHours(0,0,0,0);
  const jan1PHT = toPHT(jan1);
  const days = Math.floor((dPHT - jan1PHT) / 86400000);
  const week = Math.floor((days + jan1PHT.getDay()) / 7) + 1;
  return `${year}-W${String(week).padStart(2, '0')}`;
};

// Table Initials (Projects -> PROJ)
const tableInitials = (name) => {
  const map = {
    'Projects': 'PROJ',
    'Virtual Assistants': 'VA',
    'Placements Requirements': 'PR',
    'PDEV Requirements': 'PDEV',
    'PDEV Ongoing Requirements': 'PDEV',
  };
  if (map[name]) return map[name];

  const words = String(name || '').split(/[^A-Za-z0-9]+/).filter(Boolean);
  if (words.length === 0) return 'GEN';

  const allCaps = words.join('').match(/^[A-Z0-9]{2,}$/);
  if (allCaps) return allCaps[0].slice(0, 6);

  return words.map(w => w[0].toUpperCase()).join('').slice(0, 6);
};

// Safe JSON Parser
const tryParse = (v) => {
  if (v == null) return null;
  if (Array.isArray(v) || typeof v === 'object') return v;
  if (typeof v !== 'string') return null;
  try { return JSON.parse(v); } catch (e) { return null; }
};

// Split line helper (Replaces the IIFE that caused the error)
const splitLineInfo = (line) => {
  const separators = [' — ', ' – ', ' - '];
  for (const sep of separators) {
    const idx = line.lastIndexOf(sep);
    if (idx > 0 && idx < line.length - sep.length) {
      return [line.slice(0, idx), line.slice(idx + sep.length)];
    }
  }
  return [line, ""];
};

// 3. Compute Dates (PHT)
const nowPHT = toPHT(new Date());
const day_key = yyyymmddNum(nowPHT);
const weekStart = sundayStartPHT(nowPHT);
const week_key = yyyymmddNum(weekStart);
const week_start_pht = weekStart.toISOString();
const week_label_plain = weekLabelUS(nowPHT);

// 4. Normalize Aggregates
const table_name = agg.table_name || agg.table || agg.Table || 'Projects';
const initials = tableInitials(table_name);
const week_label = `${week_label_plain}-${initials}`;

const scanned = agg.scanned ?? agg.Scanned ?? 0;
const flagged = agg.flagged ?? agg.Flagged ?? 0;
const cleared = agg.cleared ?? agg.Cleared ?? 0;
// Use safe access for execution ID
const run_id = agg.run_id ?? agg.RunID ?? ($execution ? $execution.id : null);

let top_missing_json = agg.top_missing_json ?? agg['Top Missing (JSON)'] ?? [];
if (typeof top_missing_json === 'string') {
  try { top_missing_json = JSON.parse(top_missing_json); } catch (e) { /* ignore */ }
}

const for_scrubbing_count = agg.for_scrubbing_count ?? flagged;

// 5. Parse Passthroughs
const display_missing_records = agg.display_missing_records ?? agg['Display Missing Records'] ?? '';

let display_missing_records_lines = agg.display_missing_records_lines ?? agg['Display Missing Records (Lines)'] ?? [];
if (typeof display_missing_records_lines === 'string') {
  try {
    display_missing_records_lines = JSON.parse(display_missing_records_lines);
  } catch (e) {
    display_missing_records_lines = display_missing_records
      ? String(display_missing_records).split(/\r?\n/).filter(Boolean)
      : [];
  }
}

let display_missing_records_json = agg.display_missing_records_json ?? agg['Display Missing Records (JSON)'] ?? [];
if (typeof display_missing_records_json === 'string') {
  try { display_missing_records_json = JSON.parse(display_missing_records_json); } catch (e) { display_missing_records_json = []; }
}

// 6. Hydrate IDs (Merge various JSON sources)
const topRecordsJSON = tryParse(agg['Top Records (JSON)']) || tryParse(agg.top_records_json);
const nameToIdMap    = tryParse(agg['Name→ID Map (JSON)']) || tryParse(agg.name_id_map_json) || {};
const topIdsArray    = tryParse(agg['Top Record IDs (JSON)']) || tryParse(agg.top_record_ids_json) || [];
const topNamesArray  = tryParse(agg['Top Names (JSON)']) || tryParse(agg.top_names_json) || [];

// Build Name->ID Map
const nameToId = {};
if (topRecordsJSON && Array.isArray(topRecordsJSON)) {
  for (const r of topRecordsJSON) {
    const nm = (r?.name || '').toString().trim();
    const id = (r?.id || '').toString().trim();
    if (nm && id) nameToId[nm] = id;
  }
}
if (nameToIdMap && typeof nameToIdMap === 'object') {
  for (const [nm, id] of Object.entries(nameToIdMap)) {
    const n = (nm || '').toString().trim();
    const i = (id || '').toString().trim();
    if (n && i) nameToId[n] = i;
  }
}

// Check if we can use positional matching
const hasPositional = Array.isArray(topIdsArray) &&
  (Array.isArray(topNamesArray) ? topNamesArray.length === topIdsArray.length : true);

// Create Base Object Array
let baseArray = [];
if (Array.isArray(display_missing_records_json) && display_missing_records_json.length) {
  baseArray = display_missing_records_json.map(x => ({
    name: x.name || x.display_name || x.title || "",
    missing: Array.isArray(x.missing) ? x.missing : (Array.isArray(x.missing_fields) ? x.missing_fields : []),
    missing_count: (x.missing_count != null) ? x.missing_count : 0,
    id: x.id || x.recId || null,
  }));
} else {
  // Fallback: Parse from text lines
  baseArray = display_missing_records_lines.map(line => {
    const parts = splitLineInfo(line); // Uses the new helper function
    const name = parts[0].replace(/^\s*[•\u2022-]\s*/, '').trim();
    const fieldsStr = parts[1];

    // Extract "more" count if exists
    let extra = 0;
    const moreMatch = fieldsStr.match(/\+(\d+)\s*more/i);
    if (moreMatch) extra = Number(moreMatch[1]);

    const fields = fieldsStr
      .split(/[;,]/)
      .map(s => s.trim())
      .filter(Boolean)
      .map(s => s.replace(/[.\s]+$/g, ''))
      .filter(s => !/^\+\d+\s*more$/i.test(s)); // remove the "+X more" text from list

    return {
      name,
      missing: fields,
      missing_count: fields.length + extra,
      id: null,
    };
  });
}

// Final Enrichment
const display_missing_json = baseArray.map((row, idx) => {
  let id = row.id || null;
  const nameTrim = (row.name || '').toString().trim();

  // Try to find ID by Name
  if (!id && nameTrim && nameToId[nameTrim]) {
    id = nameToId[nameTrim];
  }
  // Try to find ID by Position
  if (!id && hasPositional && idx < (topIdsArray?.length || 0)) {
    const posId = (topIdsArray[idx] || '').toString().trim();
    if (posId) id = posId;
  }

  return {
    id: id || null,
    name: nameTrim || "(No name)",
    missing: Array.isArray(row.missing) ? row.missing : [],
    missing_count: row.missing_count != null ? row.missing_count : 0,
  };
});

const date_pht = nowPHT.toISOString();

// 7. Return Result
return [{
  json: {
    table: table_name,
    date_scrubbed: date_pht,
    run_id,
    scanned,
    flagged,
    cleared,
    for_scrubbing_count,
    top_missing_json,
    day_key,
    date_pht,
    week_key,
    week_start_pht,
    week_label,
    week_label_plain,
    table_initials: initials,

    // Passthroughs
    display_missing_records,
    display_missing_records_lines,
    display_missing_records_json,

    // Calculated JSON
    display_missing_json,
    "Display Missing (JSON)": JSON.stringify(display_missing_json)
  }
}];

/***** PDEV → Airtable updater (Updated Fields + Process Only Logic) *****/
const rec = $input.item?.json ?? {};
const id  = typeof rec.id === "string" ? rec.id.trim() : "";

// helpers to read from either flat or { fields: {...} } shapes
const get = (name) => rec[name] !== undefined ? rec[name] : rec.fields?.[name];
const has = (name) =>
  rec[name] !== undefined ||
  (rec.fields && Object.prototype.hasOwnProperty.call(rec.fields, name));

const isEmpty = (v) =>
  v == null
    ? true
    : Array.isArray(v)
      ? v.length === 0
      : (typeof v === "string" ? v.trim() === "" : false);

if (!id) {
  return { json: { _skip: true, reason: "missing id", sourceIndex: $itemIndex } };
}

/** ── Config ────────────────────────────────────────────────────────────── **/
const STATUS_FIELD_CANDIDATES = ["Status", "PDEV Status", "Requirement Status"];
const INITIAL_PEC_FIELD_CANDIDATES = ["INITIAL PEC", "Initial PEC", "Initial Pec"];
const REQ_TYPE_FIELD_CANDIDATES = ["REQ TYPE", "Req Type", "Request Type"];

const ONGOING_STATUSES = new Set(["Ongoing", "In Progress", "Active"]);
const OVERDUE_DAYS = 14;   // PEC older than this ⇒ overdue
/** ─────────────────────────────────────────────────────────────────────── **/

// 1. UPDATED: The new list of fields to check
const CHECK_FIELDS = [
  "Client",
  "Company",
  "Process Engineer",
  "POTENTIAL MVA", // <--- Skipped if Process Only
  "REQ TYPE",
  "INITIAL PEC",
  "JD + C",        // <--- Skipped if Process Only
  "VA Title",
  "Scope Type"
];

// 2. LOGIC: Determine if REQ TYPE is "PROCESS ONLY"
const normalizeText = (v) => {
  const s = (typeof v === "object" && v?.name != null) ? String(v.name) : String(v ?? "");
  return s.trim();
};

const reqTypeRaw =
  REQ_TYPE_FIELD_CANDIDATES
    .map((f) => get(f))
    .find((v) => normalizeText(v) !== "") ?? "";

const isProcessOnly = normalizeText(reqTypeRaw).toLowerCase() === "process only";

// 3. LOGIC: Filter the required fields list
// If Process Only is TRUE, we remove "POTENTIAL MVA" AND "JD + C" from the check list.
const fieldsToExclude = ["POTENTIAL MVA", "JD + C"];

const REQUIRED_FIELDS = isProcessOnly
  ? CHECK_FIELDS.filter((f) => !fieldsToExclude.includes(f))
  : CHECK_FIELDS;

let missing = REQUIRED_FIELDS.filter((name) => isEmpty(get(name)));
let actionItems = [];

// Pick the status & PEC fields that actually exist
const STATUS_FIELD = STATUS_FIELD_CANDIDATES.find((f) => has(f)) || STATUS_FIELD_CANDIDATES[0];
const PEC_FIELD    = INITIAL_PEC_FIELD_CANDIDATES.find((f) => has(f)) || INITIAL_PEC_FIELD_CANDIDATES[0];

const status = String(get(STATUS_FIELD) ?? "").trim();
const isOngoing = ONGOING_STATUSES.has(status);

const fields = {
  "Last Scrubbed At": new Date().toISOString(),
};

// 4. PEC LOGIC (Age check only)
if (isOngoing) {
  const pecRaw = get(PEC_FIELD);

  if (!isEmpty(pecRaw)) {
    // Validate/age PEC
    const pec = new Date(pecRaw);
    if (!Number.isNaN(pec.getTime())) {
      const ageDays = Math.floor((Date.now() - pec.getTime()) / 86400000);
      fields["PEC Age (days)"] = ageDays;
      const overdue = ageDays > OVERDUE_DAYS;
      fields["PEC Overdue?"] = overdue;
      if (overdue) {
        actionItems.push(`${PEC_FIELD} is ${ageDays} days old — follow up`);
      }
    } else {
      // If it exists but isn't a date, flag it
      if (!missing.includes(PEC_FIELD)) missing.push(PEC_FIELD);
      actionItems.push(`Fix invalid ${PEC_FIELD} datetime`);
    }
  }
}

// Finalize scrubbing flags & notes
fields["For Scrubbing?"] = (missing.length > 0) || fields["PEC Overdue?"] === true;
fields["Fields with Missing Data"] = missing.join(", ");
if (actionItems.length) fields["Action Items"] = actionItems.join(" • ");

// Logic Note: Helpful log for why fields were skipped
if (isProcessOnly) {
  // We append to existing notes or create new ones
  const currentNote = normalizeText(get("Notes (System)")) || "";
  const exemptionNote = "Exemptions: MVA & JD+C skipped (REQ TYPE is PROCESS ONLY)";

  // Only add the note if it isn't already there to avoid duplication on repeated runs
  if (!currentNote.includes("PROCESS ONLY")) {
     fields["Notes (System)"] = [currentNote, exemptionNote].filter(Boolean).join(" | ");
  }
}

return { json: { id, fields } };

