  - "Top Records (JSON)"     -> [{ id, name, missing?, missing_count? }]
  - "Name→ID Map (JSON)"     -> { "<name>": "rec..." }
  - "Top Record IDs (JSON)"  -> ["rec...", ...] (positional)
  - "Top Names (JSON)"       -> ["Name A", ...] (positional with Top Record IDs)
*/
const topRecordsJSON = tryParse(agg['Top Records (JSON)']) || tryParse(agg.top_records_json);
const nameToIdMap    = tryParse(agg['Name→ID Map (JSON)']) || tryParse(agg.name_id_map_json) || {};
const topIdsArray    = tryParse(agg['Top Record IDs (JSON)']) || tryParse(agg.top_record_ids_json) || [];
