      .split(/[;,]/).map(s => s.trim()).filter(Boolean)
      .map(s => s.replace(/[.\s]+$/g, ''))
      .filter(s => !/^\+\d+\s*more$/i.test(s));
    const extra = (parts[1].match(/\+(\d+)\s*more/i)?.[1]) ? Number(RegExp.$1) : 0;
    return {
