    cleared: 0,
    for_scrubbing_count: forScrubbingCount,
    top_missing_json,

    // Human
    display_missing_records: humanBlock,
    display_missing_fields:  humanBlock,

    // Structured (optional)
    display_missing_records_lines: lines,
    display_missing_records_json:  topRecordsSlim,

    // 🔗 JSON-with-IDs for the Daily row
    "Top Records (JSON)":     JSON.stringify(topRecordsSlim),
