}];

/***** Projects → Daily Scrubbing Row Prep (PHT & JSON Hydration) *****/

// 1. Get input
// (Safely handle cases where input might be empty)
const items = $input.all();
const agg = items.length > 0 && items[0].json ? items[0].json : {};

// 2. Helper Functions

// Pad numbers (01, 02...)
const pad = (n) => String(n).padStart(2, '0');

// Convert Date to PHT (UTC+8)
const toPHT = (d) => {
  const utcMs = d.getTime() + d.getTimezoneOffset() * 60000;
  return new Date(utcMs + 8 * 3600000);
};

// Get Sunday start (PHT)
const sundayStartPHT = (dPHT) => {
  const x = new Date(dPHT);
  const dow = x.getDay(); // Sun=0..Sat=6
  x.setDate(x.getDate() - dow); // rewind to Sunday
  x.setHours(0,0,0,0);
  return x;
};

// YYYYMMDD Number
const yyyymmddNum = (d) =>
  Number(`${d.getFullYear()}${pad(d.getMonth() + 1)}${pad(d.getDate())}`);

// US Week Label (e.g. 2025-W05)
const weekLabelUS = (dPHT) => {
  const year = dPHT.getFullYear();
  const jan1 = new Date(year, 0, 1);
  jan1.setHours(0,0,0,0);
  const jan1PHT = toPHT(jan1);
  const days = Math.floor((dPHT - jan1PHT) / 86400000);
  const week = Math.floor((days + jan1PHT.getDay()) / 7) + 1;
  return `${year}-W${String(week).padStart(2, '0')}`;
};

// Table Initials (Projects -> PROJ)
const tableInitials = (name) => {
  const map = {
    'Projects': 'PROJ',
    'Virtual Assistants': 'VA',
    'Placements Requirements': 'PR',
    'PDEV Requirements': 'PDEV',
    'PDEV Ongoing Requirements': 'PDEV',
  };
  if (map[name]) return map[name];

  const words = String(name || '').split(/[^A-Za-z0-9]+/).filter(Boolean);
  if (words.length === 0) return 'GEN';

  const allCaps = words.join('').match(/^[A-Z0-9]{2,}$/);
  if (allCaps) return allCaps[0].slice(0, 6);

  return words.map(w => w[0].toUpperCase()).join('').slice(0, 6);
};

// Safe JSON Parser
const tryParse = (v) => {
  if (v == null) return null;
  if (Array.isArray(v) || typeof v === 'object') return v;
  if (typeof v !== 'string') return null;
  try { return JSON.parse(v); } catch (e) { return null; }
};

// Split line helper (Replaces the IIFE that caused the error)
const splitLineInfo = (line) => {
  const separators = [' — ', ' – ', ' - '];
  for (const sep of separators) {
    const idx = line.lastIndexOf(sep);
    if (idx > 0 && idx < line.length - sep.length) {
      return [line.slice(0, idx), line.slice(idx + sep.length)];
    }
  }
  return [line, ""];
};

// 3. Compute Dates (PHT)
const nowPHT = toPHT(new Date());
