    const id = (r?.id || '').toString().trim();
    if (nm && id) nameToId[nm] = id;
  }
}
if (nameToIdMap && typeof nameToIdMap === 'object') {
  for (const [nm, id] of Object.entries(nameToIdMap)) {
    const n = (nm || '').toString().trim();
    const i = (id || '').toString().trim();
    if (n && i) nameToId[n] = i;
  }
}

// Check if we can use positional matching
const hasPositional = Array.isArray(topIdsArray) &&
  (Array.isArray(topNamesArray) ? topNamesArray.length === topIdsArray.length : true);

// Create Base Object Array
let baseArray = [];
if (Array.isArray(display_missing_records_json) && display_missing_records_json.length) {
  baseArray = display_missing_records_json.map(x => ({
    name: x.name || x.display_name || x.title || "",
    missing: Array.isArray(x.missing) ? x.missing : (Array.isArray(x.missing_fields) ? x.missing_fields : []),
    missing_count: (x.missing_count != null) ? x.missing_count : 0,
    id: x.id || x.recId || null,
  }));
} else {
  // Fallback: Parse from text lines
  baseArray = display_missing_records_lines.map(line => {
    const parts = splitLineInfo(line); // Uses the new helper function
    const name = parts[0].replace(/^\s*[•\u2022-]\s*/, '').trim();
    const fieldsStr = parts[1];

    // Extract "more" count if exists
    let extra = 0;
    const moreMatch = fieldsStr.match(/\+(\d+)\s*more/i);
    if (moreMatch) extra = Number(moreMatch[1]);

    const fields = fieldsStr
      .split(/[;,]/)
      .map(s => s.trim())
      .filter(Boolean)
      .map(s => s.replace(/[.\s]+$/g, ''))
      .filter(s => !/^\+\d+\s*more$/i.test(s)); // remove the "+X more" text from list

    return {
      name,
      missing: fields,
      missing_count: fields.length + extra,
      id: null,
    };
  });
}

// Final Enrichment
const display_missing_json = baseArray.map((row, idx) => {
  let id = row.id || null;
  const nameTrim = (row.name || '').toString().trim();

  // Try to find ID by Name
  if (!id && nameTrim && nameToId[nameTrim]) {
